#include <stdio.h>
#include <math.h>
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        double x[N], y[N], s[N];
        for (int i = 0; i < N; i++) {
            scanf("%lf %lf %lf", &x[i], &y[i], &s[i]);
        }
        double minX = x[0], maxX = x[0], minY = y[0], maxY = y[0];
        for (int i = 1; i < N; i++) {
            minX = fmin(minX, x[i]);
            maxX = fmax(maxX, x[i]);
            minY = fmin(minY, y[i]);
            maxY = fmax(maxY, y[i]);
        }
        double ans = 1e18;
        for (double X = minX; X <= maxX; X += 1) {
            for (double Y = minY; Y <= maxY; Y += 1) {
                double maxTime = 0;
                for (int i = 0; i < N; i++) {
                    double time = sqrt((X - x[i]) * (X - x[i]) + (Y - y[i]) * (Y - y[i])) / s[i];
                    maxTime = fmax(maxTime, time);
                }
                ans = fmin(ans, maxTime);
            }
        }
        printf("%.6f\n", ans);
    }
    return 0;
}

