const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let t = 0; t < T; t++) {
    const N = parseInt(readline());
    const x = [], y = [], s = [];
    for (let i = 0; i < N; i++) {
        const [xi, yi, si] = readline().split(' ').map(Number);
        x.push(xi);
        y.push(yi);
        s.push(si);
    }
    const minX = Math.min(...x), maxX = Math.max(...x), minY = Math.min(...y), maxY = Math.max(...y);
    let ans = 1e18;
    for (let X = minX; X <= maxX; X++) {
        for (let Y = minY; Y <= maxY; Y++) {
            let maxTime = 0;
            for (let i = 0; i < N; i++) {
                const time = Math.sqrt((X - x[i]) ** 2 + (Y - y[i]) ** 2) / s[i];
                maxTime = Math.max(maxTime, time);
            }
            ans = Math.min(ans, maxTime);
        }
    }
    console.log(ans.toFixed(6));
}
